import fs from 'fs';
import path from 'path';

const file = path.join(process.cwd(), 'dist/index.html');

if (fs.existsSync(file)) {
  let content = fs.readFileSync(file, 'utf-8');

  // 1. Remove all carriage returns which STACK hates
  content = content.replace(/\r/g, '');
  
  // To avoid accidentally matching strings like "<style>" or "<script>" inside the minified React DOM Javascript,
  // we will parse out only the exact tags generated by vite-plugin-singlefile

  // 2. Base64 encode the <style> block
  const styleStartMarker = '<style ';
  let styleStartIndex = content.indexOf(styleStartMarker);
  while (styleStartIndex !== -1) {
    const styleEndMarker = '</style>';
    const styleEndIndex = content.indexOf(styleEndMarker, styleStartIndex);
    if (styleEndIndex !== -1) {
      const tagEnd = content.indexOf('>', styleStartIndex);
      if (tagEnd !== -1 && tagEnd < styleEndIndex) {
        const inner = content.substring(tagEnd + 1, styleEndIndex);
        const b64 = Buffer.from(inner, 'utf-8').toString('base64');
        const replacement = `<script>
(function(){
  function d(str) {
    return decodeURIComponent(atob(str).split('').map(function(c) {
      return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
    }).join(''));
  }
  var style = document.createElement('style');
  style.textContent = d("${b64}");
  document.head.appendChild(style);
})();
</script>`;
        content = content.substring(0, styleStartIndex) + replacement + content.substring(styleEndIndex + styleEndMarker.length);
        styleStartIndex = content.indexOf(styleStartMarker, styleStartIndex + replacement.length);
        continue;
      }
    }
    break;
  }

  // 3. Base64 encode the <script type="module" crossorigin> block
  const scriptStartMarker = '<script type="module" crossorigin>';
  let scriptStartIndex = content.indexOf(scriptStartMarker);
  while (scriptStartIndex !== -1) {
    const scriptEndMarker = '</script>';
    const scriptEndIndex = content.indexOf(scriptEndMarker, scriptStartIndex);
    if (scriptEndIndex !== -1) {
      const inner = content.substring(scriptStartIndex + scriptStartMarker.length, scriptEndIndex);
      const b64 = Buffer.from(inner, 'utf-8').toString('base64');
      const replacement = `<script type="module" crossorigin>
(function(){
  function d(str) {
    return decodeURIComponent(atob(str).split('').map(function(c) {
      return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
    }).join(''));
  }
  function init() {
    var script = document.createElement('script');
    script.type = "module";
    script.textContent = d("${b64}");
    document.body.appendChild(script);
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
</script>`;
      content = content.substring(0, scriptStartIndex) + replacement + content.substring(scriptEndIndex + scriptEndMarker.length);
      scriptStartIndex = content.indexOf(scriptStartMarker, scriptStartIndex + replacement.length);
      continue;
    }
    break;
  }

  // 4. In case any "{@" or "{#" remain in the raw HTML body, break them apart
  content = content.replace(/\{@/g, '{ @');
  content = content.replace(/\{#/g, '{ #');

  fs.writeFileSync(file, content);
  fs.writeFileSync(path.join(process.cwd(), 'dist/molecule-editor.html'), content);
  fs.writeFileSync(path.join(process.cwd(), 'public/molecule-editor.html'), content);
  console.log('Secured HTML against STACK CASText parser by Base64 encoding scripts and styles.');
}


